//! Measures whether a synthetic document (generated by `synthpass-gen`)
//! survives the same Tier-1 pipeline real documents go through: OCR
//! (`synthpass-ocr`) followed by ICAO 9303 checksum validation (`mrz`).
//!
//! This is deliberately a real integration measurement, not a unit test of
//! the generator or the OCR engine in isolation — it exists to answer "does
//! the rendered image actually OCR back to a checksum-valid MRZ matching the
//! ground truth," the same question `crates/synthpass-ocr/examples/
//! mrz_corpus.rs` answers for the real `samples/` corpus, factored here into
//! a reusable library instead of example-local logic.

use image::DynamicImage;
use std::time::{Duration, Instant};
use synthpass_gen::Labels;
use synthpass_ocr::NativeOcr;

/// Outcome of running one generated document through OCR + checksum
/// validation.
#[derive(Debug, Clone)]
pub struct HitResult {
    /// `true` iff OCR recovered a checksum-valid MRZ whose document number
    /// matches the generator's ground truth.
    pub hit: bool,
    /// Human-readable reason for a miss (OCR error, no MRZ found, checksum
    /// failed, document number mismatch). `None` on a hit.
    pub reason: Option<String>,
    /// Wall-clock time spent in this check (OCR + parse), for reporting.
    pub elapsed: Duration,
}

/// Runs `image` through `ocr` and checks the result against `expected`'s
/// ground-truth MRZ. Writes `image` to a temporary file first — neither
/// `NativeOcr::recognize` nor the pipeline's `OcrEngine` trait expose an
/// in-memory entry point today, so a temp file is the same pattern every
/// other OCR call site in this workspace already uses.
pub fn check_document(ocr: &NativeOcr, image: &DynamicImage, expected: &Labels) -> HitResult {
    let start = Instant::now();

    let path = std::env::temp_dir().join(format!(
        "synthpass-bench-{}-{}.png",
        std::process::id(),
        fastrand_seed()
    ));
    let write_result = image.save(&path);
    let result = run_check(&path, write_result, ocr, expected);
    let _ = std::fs::remove_file(&path);

    HitResult {
        hit: result.is_ok(),
        reason: result.err(),
        elapsed: start.elapsed(),
    }
}

fn run_check(
    path: &std::path::Path,
    write_result: image::ImageResult<()>,
    ocr: &NativeOcr,
    expected: &Labels,
) -> Result<(), String> {
    write_result.map_err(|e| format!("failed to write temp image: {e}"))?;

    let text = ocr.recognize(path)?;

    let decoded = mrz::find_and_parse(&text).map_err(|e| format!("no MRZ found: {e:?}"))?;

    if !decoded.valid() {
        return Err(format!("checksum invalid: {:?}", decoded.checks));
    }

    if decoded.document_number != expected.document_number.value {
        return Err(format!(
            "document number mismatch: got {:?}, expected {:?}",
            decoded.document_number, expected.document_number.value
        ));
    }

    Ok(())
}

/// A cheap, non-cryptographic per-call disambiguator for temp file names —
/// avoids collisions when `check_document` is called many times in the same
/// process within the same millisecond (the process ID alone isn't enough).
fn fastrand_seed() -> u64 {
    use std::sync::atomic::{AtomicU64, Ordering};
    static COUNTER: AtomicU64 = AtomicU64::new(0);
    COUNTER.fetch_add(1, Ordering::Relaxed)
}

#[cfg(test)]
mod tests {
    use super::*;
    use synthpass_gen::{generate_from_seed, GeneratorConfig};

    /// Needs the real `.rten` OCR models at the repo root — same requirement
    /// as `crates/synthpass-ocr/tests/native_ocr_e2e.rs`, run with
    /// `cargo test -p synthpass-bench -- --ignored`.
    ///
    /// Checks a handful of seeds and requires at least one hit rather than
    /// asserting a specific seed or rate: this proves the OCR + checksum
    /// wiring actually works end to end, without duplicating the aggregate
    /// hit-rate measurement that `synthpass-bench`'s corpus runner binary
    /// owns (real-world hit rate on generated documents is well under 100%,
    /// see the M4 benchmark report).
    #[test]
    #[ignore]
    fn some_clean_generated_documents_hit() {
        let root = repo_root();
        let ocr = NativeOcr::load(
            &root.join("text-detection.rten"),
            &root.join("text-recognition.rten"),
        )
        .expect("failed to load OCR models — run from the repo root");

        let mut results = Vec::new();
        for seed in 0..5 {
            let config = GeneratorConfig::new(seed);
            let (image, labels, _passport) = generate_from_seed(&config);
            results.push(check_document(&ocr, &image, &labels));
        }

        assert!(
            results.iter().any(|r| r.hit),
            "expected at least one hit across 5 seeds, got: {:?}",
            results.iter().map(|r| &r.reason).collect::<Vec<_>>()
        );
    }

    fn repo_root() -> std::path::PathBuf {
        std::path::Path::new(env!("CARGO_MANIFEST_DIR"))
            .ancestors()
            .nth(2)
            .expect("crates/synthpass-bench is two levels below the repo root")
            .to_path_buf()
    }
}
